import requests
import json

def create_service(kong_host, kong_port, service_name, host):
    url = f'http://{kong_host}:{kong_port}/apis'
    data = {
        'host': service_name,
        'upstream_service_id': ''
    }
    response = requests.post(url, headers={'Content-Type': 'application/json'}, data=json.dumps(data))
    if response.status_code == 201:
        print(f'Service {service_name} created successfully')
    else:
        print('Failed to create service')

def add_route(kong_host, kong_port, service_name, route):
    url = f'http://{kong_host}:{kong_port}/apis/{service_name}/routes'
    data = {
        'hosts': [route['host']],
        'paths': [route['path']]
    }
    response = requests.post(url, headers={'Content-Type': 'application/json'}, data=json.dumps(data))
    if response.status_code == 201:
        print(f'Route {route["path"]} created successfully')
    else:
        print('Failed to create route')

def add_upstream_target(kong_host, kong_port, service_name, host):
    url = f'http://{kong_host}:{kong_port}/services/{service_name}/upstreams'
    data = {
        'name': service_name,
        'hosts': [host]
    }
    response = requests.post(url, headers={'Content-Type': 'application/json'}, data=json.dumps(data))
    if response.status_code == 201:
        print(f'Upstream target {service_name} created successfully')
    else:
        print('Failed to create upstream target')

kong_host = 'localhost'
kong_port = 8001
services = [
    {'name': 'service-01', 'host': 'service-01'},
    {'name': 'service-02', 'host': 'service-02'}
]
routes = [
    {'path': '/route-01', 'host': 'route-01'},
    {'path': '/route-02', 'host': 'route-02'}
]

for service in services:
    create_service(kong_host, kong_port, service['name'], service['host'])

for route in routes:
    add_route(kong_host, kong_port, route['host'].split('.')[0], route)

for service in services:
    add_upstream_target(kong_host, kong_port, service['name'], service['host'])